    <div className="Footer-Socials">
      <a href="http://insagram.com" className="Footer-Instagram link-socials">{}</a>
      <a href="http://twitter.com" className="Footer-Twitter link-">{}</a>
      <a href="http://linkedin.com" className="Footer-LinkedIn link">{}</a>
    </div>
  </footer>
);
